  tg_actor_hint: { nl: "Kies de prior beheerder namens wie je wijzigingen doorvoert.", fr: "Choisissez l’administrateur prior au nom duquel vous effectuez les modifications.", en: "Choose the prior administrator on whose behalf you make changes.", es: "Elige el administrador prior en cuyo nombre realizas los cambios.", ru: "Выберите приор-администратора, от имени которого вы вносите изменения." },
