  admin_intro: { nl: "Beheer afnames, verstuur uitnodigingen en volg de voortgang op.", fr: "Gérez les évaluations, envoyez des invitations et suivez la progression.", en: "Manage assessments, send invitations and track progress.", es: "Gestiona las evaluaciones, envía invitaciones y sigue el progreso.", ru: "Управляйте прохождениями, отправляйте приглашения и отслеживайте ход." },
