  admin_dialog_uitleg: { nl: "Maak een persoonlijke link aan. De taal wordt vastgelegd bij het aanmaken.", fr: "Créez un lien personnel. La langue est fixée à la création.", en: "Create a personal link. The language is set at creation.", es: "Crea un enlace personal. El idioma se fija al crearlo.", ru: "Создайте персональную ссылку. Язык фиксируется при создании." },
