  t4r_sessie_vergrendel_intro: { nl: "Vergrendel de kring om de individuele input te starten. Hierbij wordt het sessietarief gereserveerd.", fr: "Verrouillez le cercle pour démarrer la contribution individuelle. Le tarif de session est alors réservé.", en: "Lock the circle to start individual input. This reserves the session fee.", es: "Bloquea el círculo para iniciar la aportación individual. Esto reserva la tarifa de sesión.", ru: "Заблокируйте круг для начала индивидуального ввода. При этом резервируется тариф сеанса." },
  t4r_sessie_kring_vergrendelen: { nl: "Kring vergrendelen", fr: "Verrouiller le cercle", en: "Lock circle", es: "Bloquear círculo", ru: "Заблокировать круг" },
  t4r_sessie_geen_platform: { nl: "Deze sessie is niet aan een platform-traject gekoppeld; kringbeheer is niet beschikbaar.", fr: "Cette session n'est pas liée à un trajet de plateforme ; la gestion du cercle n'est pas disponible.", en: "This session is not linked to a platform trajectory; circle management is not available.", es: "Esta sesión no está vinculada a un trayecto de plataforma; la gestión del círculo no está disponible.", ru: "Этот сеанс не связан с платформенным маршрутом; управление кругом недоступно." },
