  t4r_comp_report_sluit: { nl: "Sluit en vergrendel", fr: "Fermer et verrouiller", en: "Close and lock", es: "Cerrar y bloquear", ru: "Закрыть и заблокировать" },
  t4r_comp_report_vergrendeld: { nl: "Sessie afgesloten en vergrendeld. Alleen rapporten zijn nog raadpleegbaar.", fr: "Session clôturée et verrouillée. Seuls les rapports sont encore consultables.", en: "Session closed and locked. Only reports can still be consulted.", es: "Sesión cerrada y bloqueada. Solo se pueden consultar los informes.", ru: "Сеанс закрыт и заблокирован. Доступны только отчёты." },
  t4r_comp_report_talentmotor: { nl: "De talentmotor in één oogopslag", fr: "Le moteur de talent en un coup d'oeil", en: "The talent engine at a glance", es: "El motor de talento de un vistazo", ru: "Двигатель таланта с первого взгляда" },
  t4r_comp_report_talentmotor_intro: { nl: "De drie profieldimensies samengebracht. Per dimensie staan de gekozen kenmerken op volgorde van belang: kritische need to have eerst, dan need, nice en tot slot not needed.", fr: "Les trois dimensions du profil réunies. Par dimension, les caractéristiques choisies sont dans l'ordre d'importance : besoins critiques en premier, puis indispensables, souhaitables et enfin non nécessaires.", en: "The three profile dimensions brought together. Per dimension, the chosen characteristics are in order of importance: critical need to have first, then need, nice, and finally not needed.", es: "Las tres dimensiones del perfil reunidas. Por dimensión, las características elegidas están en orden de importancia: las necesidades críticas primero, luego las indispensables, las deseables y por último las no necesarias.", ru: "Три измерения профиля собраны воедино. По каждому измерению выбранные характеристики расположены в порядке важности: сначала критические обязательные, затем обязательные, желательные и наконец ненужные." },
  t4r_comp_report_zelfbeeld_titel: { nl: "Zelfbeeld en innerlijke oriëntatie", fr: "Image de soi et orientation intérieure", en: "Self-image and inner orientation", es: "Autoimagen y orientación interior", ru: "Самообраз и внутренняя ориентация" },
  t4r_comp_report_zelfbeeld_intro: { nl: "Een aparte laag, los van talent. Dit raakt aan dieperliggende eigenschappen — zelfkennis, waardengedrevenheid en zelfzekerheid — die meer bepalen dan talent alleen. Op volgorde van belang.", fr: "Une couche distincte, indépendante du talent. Cela touche à des propriétés plus profondes — connaissance de soi, orientation par les valeurs et assurance — qui déterminent davantage que le talent seul. Par ordre d'importance.", en: "A separate layer, independent of talent. This touches on deeper properties — self-knowledge, value-driven orientation and self-confidence — that determine more than talent alone. In order of importance.", es: "Una capa separada, independiente del talento. Esto toca propiedades más profundas — autoconocimiento, orientación por valores y autoconfianza — que determinan más que el talento solo. En orden de importancia.", ru: "Отдельный пласт, независимый от таланта. Это касается более глубоких свойств — самопознания, ценностной ориентации и уверенности в себе — которые определяют больше, чем один талент. В порядке важности." },
  t4r_comp_report_vrijgave: { nl: "Vrijgegeven op basis van alignment", fr: "Publié sur la base de l'alignement", en: "Released on the basis of alignment", es: "Publicado sobre la base de la alineación", ru: "Выпущено на основе выравнивания" },
  t4r_comp_report_vrijgave_intro: { nl: "Dit profiel berust op alignment, niet op consensus. Consensus middelt verschillen weg en levert een vlak profiel waar niemand echt achter staat. Alignment is een bewuste, toekomstgerichte en gedragen keuze die elke stemgerechtigde stakeholder expliciet onderschrijft — restverschillen worden benoemd, niet verstopt.", fr: "Ce profil repose sur l'alignement, pas sur le consensus. Le consensus gomme les différences et produit un profil plat que personne ne soutient vraiment. L'alignement est un choix conscient, tourné vers l'avenir et assumé, explicitement approuvé par chaque partie prenante habilitée à voter — les différences résiduelles sont nommées, pas cachées.", en: "This profile rests on alignment, not consensus. Consensus averages away differences and produces a flat profile that nobody truly stands behind. Alignment is a conscious, forward-looking, and supported choice that every eligible voting stakeholder explicitly endorses — residual differences are named, not hidden.", es: "Este perfil se basa en la alineación, no en el consenso. El consenso promedia las diferencias y produce un perfil plano que nadie apoya realmente. La alineación es una elección consciente, orientada al futuro y respaldada que cada parte interesada con derecho a voto respalda explícitamente: las diferencias residuales se nombran, no se ocultan.", ru: "Этот профиль основан на выравнивании, а не на консенсусе. Консенсус нивелирует различия и производит плоский профиль, который никто по-настоящему не поддерживает. Выравнивание — это осознанный, перспективный и поддерживаемый выбор, который каждый правомочный стейкхолдер явно одобряет — остаточные различия называются, а не скрываются." },
  t4r_comp_report_functie: { nl: "Functie / opdracht", fr: "Fonction / mission", en: "Function / assignment", es: "Función / encargo", ru: "Функция / задание" },
