  t4r_comp_report_stakeholders: { nl: "stakeholders", fr: "parties prenantes", en: "stakeholders", es: "partes interesadas", ru: "стейкхолдеры" },
  t4r_comp_report_essentieel: { nl: "Het gewenste profiel telt {n} essentiële (need to have) kenmerken, waarvan {k} als kritisch succescriterium gemarkeerd.", fr: "Le profil souhaité compte {n} caractéristiques essentielles (indispensables), dont {k} marquées comme critères de succès critiques.", en: "The desired profile counts {n} essential (need to have) characteristics, of which {k} are marked as critical success criteria.", es: "El perfil deseado cuenta con {n} características esenciales (imprescindibles), de las cuales {k} están marcadas como criterios de éxito críticos.", ru: "Желаемый профиль насчитывает {n} существенных (обязательных) характеристик, из которых {k} отмечены как критические критерии успеха." },
