  t4r_comp_report_footer: { nl: "TAPAS 4 Recruitment · gezamenlijke profielconstructie", fr: "TAPAS 4 Recruitment · construction de profil conjointe", en: "TAPAS 4 Recruitment · joint profile construction", es: "TAPAS 4 Recruitment · construcción conjunta de perfil", ru: "TAPAS 4 Recruitment · совместное построение профиля" },
  t4r_comp_sh_titel: { nl: "Stakeholderkring samenstellen", fr: "Constituer le cercle des parties prenantes", en: "Assemble stakeholder circle", es: "Constituir el círculo de partes interesadas", ru: "Собрать круг стейкхолдеров" },
  t4r_comp_sh_intro: { nl: "Leg de volledige, definitieve stakeholderset vast vóór de start. Na sluiting worden geen bijkomende stemgerechtigde deelnemers meer toegevoegd.", fr: "Établissez l'ensemble complet et définitif des parties prenantes avant le début. Après clôture, aucun participant supplémentaire habilité à voter ne sera ajouté.", en: "Establish the complete, definitive stakeholder set before the start. After closure, no additional eligible voting participants will be added.", es: "Establece el conjunto completo y definitivo de partes interesadas antes del inicio. Después del cierre, no se añadirán más participantes con derecho a voto.", ru: "Установите полный, окончательный состав стейкхолдеров до начала. После закрытия дополнительные правомочные участники голосования не добавляются." },
